from sqlalchemy import create_engine, text

engine = create_engine("postgresql+psycopg2://user:pass@localhost/mydb")

with engine.connect() as conn:
    result = conn.execution_options(yield_per=10_000).execute(
        text("SELECT * FROM events WHERE status = 'active'")
    )

    for partition in result.partitions(10_000):
        # partition is a list of Row objects
        for row in partition:
            process(row)

def extract_by_id(engine, last_id: int, batch_size: int = 100_000) -> pd.DataFrame:
    return pd.read_sql_query(
        text("SELECT * FROM events WHERE event_id > :last_id ORDER BY event_id LIMIT :batch"),
        con=engine,
        params={"last_id": last_id, "batch": batch_size}
    )

